<template><aside v-if="warnings.length" class="urgent-panel"><div class="alarm">!</div><div><small>AI CRITICAL VALUE</small><strong>{{warnings.length}} 条危急值待加急复核</strong><p>{{warnings[0].patientName}}：{{warnings[0].criticalItems}}</p></div><el-button type="danger" size="small" @click="$router.push('/history')">查看报告</el-button></aside></template>
<script setup lang="ts">import{onMounted,onUnmounted,ref}from'vue';import{useRoute}from'vue-router';import{getCriticalWarnings}from'@/api/lab';const route=useRoute(),warnings=ref<any[]>([]);let timer:number;async function load(){if(route.path==='/login'||!localStorage.getItem('token'))return;try{const r=await getCriticalWarnings();warnings.value=r.data.data.content||[]}catch{}}onMounted(()=>{load();timer=window.setInterval(load,30000)});onUnmounted(()=>clearInterval(timer))</script>
<style scoped>.urgent-panel{position:fixed;z-index:2500;right:26px;bottom:24px;width:min(500px,calc(100vw - 52px));display:flex;align-items:center;gap:14px;padding:17px 19px;border:1px solid #ffbcb6;border-radius:17px;background:#fff5f3;box-shadow:0 16px 45px rgba(156,49,43,.2)}.alarm{width:43px;height:43px;flex:none;border-radius:14px;background:#ed5d52;color:#fff;display:flex;align-items:center;justify-content:center;font-size:24px;font-weight:900}.urgent-panel>div:nth-child(2){flex:1}.urgent-panel small,.urgent-panel strong,.urgent-panel p{display:block}.urgent-panel small{color:#df5c53;font-size:9px;letter-spacing:1.4px}.urgent-panel strong{margin-top:2px;color:#7d292b;font-size:14px}.urgent-panel p{margin:5px 0 0;color:#765b5c;font-size:11px;line-height:1.45}</style>
